var data = ($.steps.scrapePage.response && $.steps.scrapePage.response.data) ? $.steps.scrapePage.response.data : {};
var markdown = (data.markdown || '').slice(0, 8000);
return { markdown: markdown, url: $.input.targetUrl };

var content = $.steps.extractContent.output;
var prompt = 'You are a lead generation specialist. Extract and clean business lead data from the following scraped web content.

';
prompt += 'SOURCE URL: ' + content.url + '
';
prompt += 'LEAD TYPE: ' + ($.input.leadType || 'business leads') + '

';
prompt += 'SCRAPED CONTENT:
' + content.markdown + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Extract every identifiable business or contact from the content
';
prompt += '- Clean and standardize all data (proper capitalization, format phone numbers, validate emails)
';
prompt += '- Remove duplicates
';
prompt += '- Categorize each lead by quality: Hot, Warm, or Cold

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "leads": [
';
prompt += '    {
';
prompt += '      "businessName": "...",
';
prompt += '      "contactName": "...",
';
prompt += '      "email": "...",
';
prompt += '      "phone": "...",
';
prompt += '      "address": "...",
';
prompt += '      "website": "...",
';
prompt += '      "category": "...",
';
prompt += '      "quality": "Hot|Warm|Cold",
';
prompt += '      "notes": "..."
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "totalLeads": 0,
';
prompt += '  "summary": "Brief summary of leads found"
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { leads: [], totalLeads: 0, summary: raw }; }

var ai = $.steps.parseAI.output;
var leads = ai.leads || [];
var date = new Date().toISOString().split('T')[0];
var leadType = $.input.leadType || 'Business';
var sheetData = leads.map(function(l, i) {
  return {
    'No': i + 1,
    'Business Name': l.businessName || '',
    'Contact Name': l.contactName || '',
    'Email': l.email || '',
    'Phone': l.phone || '',
    'Address': (l.address || '').slice(0, 200),
    'Website': l.website || '',
    'Category': l.category || '',
    'Quality': l.quality || '',
    'Notes': (l.notes || '').slice(0, 200),
    'Source URL': $.input.targetUrl,
    'Date Scraped': date
  };
});
var sheetTitle = 'Leads - ' + leadType + ' - ' + date;
return { sheetData: sheetData, leadCount: leads.length, date: date, summary: ai.summary || '', sheetTitle: sheetTitle };
